	}
	if err := r.setupAuth(r.homeDir); err != nil {
		return nil, fmt.Errorf("error configuring the credentials: %w", err)
	}
	return r, nil
}

func (r *repo) Close() error {
	return os.RemoveAll(r.homeDir)
}

